sparql_query:
PREFIX goo:    <https://ucf-henat.github.io/GeoOutageOnto/#>
PREFIX gokg:   <http://example.org/resource#>
PREFIX xsd:    <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf:    <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs:   <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?county ?state ?sviRecord ?housingTransportationScore ?floodEventCount
WHERE {
  ?state a goo:State ;
         goo:neighboringStates gokg:FloridaState .
  ?county a goo:County ;
          goo:locatedInState ?state .
  ?sviRecord a goo:SVIRecord ;
             goo:representsCounty ?county ;
             goo:sviYear 2022 ;
             goo:sviHousingTransportationTheme ?housingTransportationScore .
  FILTER (?housingTransportationScore >= 0.85)
  {
    SELECT ?county ?state (COUNT(DISTINCT ?event) AS ?floodEventCount)
    WHERE {
      ?event a goo:StormEventRecord ;
             goo:occurredInState ?state ;
             goo:occurredInCounty ?county ;
             goo:stormEventType ?eventType ;
             goo:eventStartTime ?eventStart .
      FILTER (YEAR(?eventStart) = 2022)
      FILTER (REGEX(STR(?eventType), "flood", "i"))
    }
    GROUP BY ?county ?state
  }
  FILTER (?floodEventCount >= 5)
}
ORDER BY DESC(?housingTransportationScore) DESC(?floodEventCount) ?county
LIMIT 10
